# Let me verify my understanding of how shapes open and reds match

for i, s in enumerate(train_samples):
    inp = np.array(s['input'])
    out = np.array(s['output'])
    bg = int(np.bincount(inp.flatten()).argmax())
    colors = set(int(x) for x in np.unique(inp)) - {bg, 2}
    shape_color = list(colors)[0]

    comps = get_connected_components(inp.tolist(), shape_color)
    red_comps = get_connected_components(inp.tolist(), 2)

    print(f"=== Example {i} ===")

    for j, comp in enumerate(comps):
        cells = set(comp)
        rows = [r for r,c in comp]
        cols = [c for r,c in comp]
        min_r, max_r = min(rows), max(rows)
        min_c, max_c = min(cols), max(cols)

        # Determine opening direction
        top_count = sum(1 for r,c in comp if r == min_r)
        bottom_count = sum(1 for r,c in comp if r == max_r)
        left_count = sum(1 for r,c in comp if c == min_c)
        right_count = sum(1 for r,c in comp if c == max_c)

        bar_side = max({'top': top_count, 'bottom': bottom_count, 'left': left_count, 'right': right_count}, 
                       key={'top': top_count, 'bottom': bottom_count, 'left': left_count, 'right': right_count}.get)

        opening = {'top': 'bottom', 'bottom': 'top', 'left': 'right', 'right': 'left'}[bar_side]

        print(f"  Shape {j}: opening={opening}")

        # Try to match with each red component
        for k, red_comp in enumerate(red_comps):
            red_cells = set(red_comp)
            red_rows = [r for r,c in red_comp]
            red_cols = [c for r,c in red_comp]
            red_min_r, red_max_r = min(red_rows), max(red_rows)
            red_min_c, red_max_c = min(red_cols), max(red_cols)

            # Check if red is on the opening side and aligned
            on_opening_side = False
            if opening == 'bottom' and red_min_r > max_r:
                on_opening_side = True
            elif opening == 'top' and red_max_r < min_r:
                on_opening_side = True
            elif opening == 'right' and red_min_c > max_c:
                on_opening_side = True
            elif opening == 'left' and red_max_c < min_c:
                on_opening_side = True

            if on_opening_side:
                # Check alignment - for vertical movement, cols must overlap with interior
                # For horizontal movement, rows must overlap with interior
                # Interior: cells in bbox that are NOT shape cells
                interior_rows = set()
                interior_cols = set()
                for r in range(min_r, max_r+1):
                    for c in range(min_c, max_c+1):
                        if (r,c) not in cells:
                            interior_rows.add(r)
                            interior_cols.add(c)

                aligned = False
                if opening in ['top', 'bottom']:
                    # Red cols must be subset of interior cols
                    if set(range(red_min_c, red_max_c+1)).issubset(interior_cols):
                        aligned = True
                else:
                    if set(range(red_min_r, red_max_r+1)).issubset(interior_rows):
                        aligned = True

                if aligned:
                    print(f"    MATCH with Red {k}: ({red_min_r},{red_min_c})-({red_max_r},{red_max_c})")

                    # Calculate where red lands
                    # For each cell in red block, find distance to first shape cell
                    H, W = inp.shape
                    min_dist = float('inf')

                    if opening == 'bottom':  # red is below, moves up
                        for r, c in red_comp:
                            # scan up from r
                            for d in range(1, r+1):
                                if (r-d, c) in cells:
                                    min_dist = min(min_dist, d)
                                    break
                    elif opening == 'top':  # red is above, moves down
                        for r, c in red_comp:
                            for d in range(1, H-r):
                                if (r+d, c) in cells:
                                    min_dist = min(min_dist, d)
                                    break
                    elif opening == 'right':  # red is right, moves left
                        for r, c in red_comp:
                            for d in range(1, c+1):
                                if (r, c-d) in cells:
                                    min_dist = min(min_dist, d)
                                    break
                    elif opening == 'left':  # red is left, moves right
                        for r, c in red_comp:
                            for d in range(1, W-c):
                                if (r, c+d) in cells:
                                    min_dist = min(min_dist, d)
                                    break

                    shift = min_dist - 1
                    print(f"    min_dist={min_dist}, shift={shift}")

                    # New position
                    if opening == 'bottom':
                        new_cells = [(r-shift, c) for r,c in red_comp]
                    elif opening == 'top':
                        new_cells = [(r+shift, c) for r,c in red_comp]
                    elif opening == 'right':
                        new_cells = [(r, c-shift) for r,c in red_comp]
                    elif opening == 'left':
                        new_cells = [(r, c+shift) for r,c in red_comp]

                    print(f"    New position: {sorted(new_cells)}")
    print()

