def solve(grid):
    import numpy as np
    from collections import deque

    grid = [list(row) for row in grid]
    H, W = len(grid), len(grid[0])
    inp = np.array(grid)

    # Find background color
    bg = int(np.bincount(inp.flatten()).argmax())

    # Find shape color
    colors = set(int(x) for x in np.unique(inp)) - {bg, 2}
    shape_color = list(colors)[0]

    def get_cc(grid_list, color):
        visited = set()
        components = []
        for r in range(H):
            for c in range(W):
                if grid_list[r][c] == color and (r,c) not in visited:
                    comp = []
                    q = deque([(r,c)])
                    visited.add((r,c))
                    while q:
                        cr, cc = q.popleft()
                        comp.append((cr,cc))
                        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                            nr, nc = cr+dr, cc+dc
                            if 0<=nr<H and 0<=nc<W and (nr,nc) not in visited and grid_list[nr][nc] == color:
                                visited.add((nr,nc))
                                q.append((nr,nc))
                    components.append(comp)
        return components

    shapes = get_cc(grid, shape_color)
    reds = get_cc(grid, 2)

    # Start with output = input with all reds replaced by bg
    out = [row[:] for row in grid]
    for red_comp in reds:
        for r, c in red_comp:
            out[r][c] = bg

    # For each shape, find matching red and place it
    used_reds = set()

    for shape_comp in shapes:
        cells = set(shape_comp)
        rows_s = [r for r,c in shape_comp]
        cols_s = [c for r,c in shape_comp]
        min_r, max_r = min(rows_s), max(rows_s)
        min_c, max_c = min(cols_s), max(cols_s)

        # Determine opening direction
        edge_counts = {
            'top': sum(1 for r,c in shape_comp if r == min_r),
            'bottom': sum(1 for r,c in shape_comp if r == max_r),
            'left': sum(1 for r,c in shape_comp if c == min_c),
            'right': sum(1 for r,c in shape_comp if c == max_c)
        }
        bar_side = max(edge_counts, key=edge_counts.get)
        opening = {'top': 'bottom', 'bottom': 'top', 'left': 'right', 'right': 'left'}[bar_side]

        # Interior columns/rows
        interior_cols = set()
        interior_rows = set()
        for r in range(min_r, max_r+1):
            for c in range(min_c, max_c+1):
                if (r,c) not in cells:
                    interior_rows.add(r)
                    interior_cols.add(c)

        # Find matching red
        best_red_idx = None
        best_dist = float('inf')

        for k, red_comp in enumerate(reds):
            if k in used_reds:
                continue
            red_rows = [r for r,c in red_comp]
            red_cols = [c for r,c in red_comp]
            red_min_r, red_max_r = min(red_rows), max(red_rows)
            red_min_c, red_max_c = min(red_cols), max(red_cols)

            on_opening_side = False
            if opening == 'bottom' and red_min_r > max_r:
                on_opening_side = True
            elif opening == 'top' and red_max_r < min_r:
                on_opening_side = True
            elif opening == 'right' and red_min_c > max_c:
                on_opening_side = True
            elif opening == 'left' and red_max_c < min_c:
                on_opening_side = True

            if not on_opening_side:
                continue

            # Check alignment
            aligned = False
            if opening in ['top', 'bottom']:
                if set(range(red_min_c, red_max_c+1)).issubset(interior_cols):
                    aligned = True
            else:
                if set(range(red_min_r, red_max_r+1)).issubset(interior_rows):
                    aligned = True

            if not aligned:
                continue

            # Calculate distance
            if opening == 'bottom':
                dist = red_min_r - max_r
            elif opening == 'top':
                dist = min_r - red_max_r
            elif opening == 'right':
                dist = red_min_c - max_c
            elif opening == 'left':
                dist = min_c - red_max_c

            if dist < best_dist:
                best_dist = dist
                best_red_idx = k

        if best_red_idx is None:
            continue

        used_reds.add(best_red_idx)
        red_comp = reds[best_red_idx]

        # Calculate shift
        min_dist_to_shape = float('inf')
        for r, c in red_comp:
            if opening == 'bottom':  # moves up
                for d in range(1, r+1):
                    if (r-d, c) in cells:
                        min_dist_to_shape = min(min_dist_to_shape, d)
                        break
            elif opening == 'top':  # moves down
                for d in range(1, H-r):
                    if (r+d, c) in cells:
                        min_dist_to_shape = min(min_dist_to_shape, d)
                        break
            elif opening == 'right':  # moves left
                for d in range(1, c+1):
                    if (r, c-d) in cells:
                        min_dist_to_shape = min(min_dist_to_shape, d)
                        break
            elif opening == 'left':  # moves right
                for d in range(1, W-c):
                    if (r, c+d) in cells:
                        min_dist_to_shape = min(min_dist_to_shape, d)
                        break

        shift = min_dist_to_shape - 1

        # Place red at new position
        dr_map = {'bottom': (-1, 0), 'top': (1, 0), 'right': (0, -1), 'left': (0, 1)}
        dr, dc = dr_map[opening]

        new_red_cells = set()
        for r, c in red_comp:
            nr, nc = r + dr * shift, c + dc * shift
            new_red_cells.add((nr, nc))
            out[nr][nc] = 2

        # Draw trail of 0s between original and new positions
        for r, c in red_comp:
            nr, nc = r + dr * shift, c + dc * shift
            # Trail from original to just before new position
            # Actually: from (nr + dr) to (r, c) inclusive... no
            # Trail: cells between new position and original position, exclusive of new, inclusive of original
            if opening == 'bottom':  # moved up, trail goes from nr+1 to r
                for tr in range(nr + 1, r + 1):
                    out[tr][c] = 0
            elif opening == 'top':  # moved down, trail goes from r to nr-1
                for tr in range(r, nr):
                    out[tr][c] = 0
            elif opening == 'right':  # moved left, trail goes from nc+1 to c
                for tc in range(nc + 1, c + 1):
                    out[r][tc] = 0
            elif opening == 'left':  # moved right, trail goes from c to nc-1
                for tc in range(c, nc):
                    out[r][tc] = 0

    return out

# Test
for i, s in enumerate(train_samples):
    result = solve(s['input'])
    expected = s['output']
    match = result == expected
    print(f"Example {i}: {'PASS' if match else 'FAIL'}")
    if not match:
        result_np = np.array(result)
        expected_np = np.array(expected)
        diff = np.where(result_np != expected_np)
        for r, c in zip(diff[0], diff[1]):
            print(f"  ({int(r)},{int(c)}): got {int(result_np[r,c])}, expected {int(expected_np[r,c])}")

